import { MapContainer, TileLayer, Marker, Polyline, CircleMarker, useMap } from "react-leaflet"
import { useEffect, useState } from "react"
import L from "leaflet"
import "leaflet.heat"

function HeatmapLayer({ bins }) {
  const map = useMap()

  useEffect(() => {
    if (!bins.length) return

    const heatData = bins.map(b => [
      b.Latitude,
      b.Longitude,
      b.Waste_Level / 100
    ])

    const heat = L.heatLayer(heatData, {
      radius: 40,
      blur: 25,
      gradient: {
        0.2: "blue",
        0.5: "yellow",
        1.0: "red"
      }
    }).addTo(map)

    return () => map.removeLayer(heat)

  }, [bins])

  return null
}

export default function MapPage(){

  const [bins,setBins] = useState([])
  const [route,setRoute] = useState([])
  const [selected,setSelected] = useState(null)

  const [binId,setBinId] = useState("")
  const [waste,setWaste] = useState("")

  useEffect(()=>{
    fetch("http://127.0.0.1:5000/bins").then(r=>r.json()).then(setBins)
    fetch("http://127.0.0.1:5000/route").then(r=>r.json()).then(setRoute)
  },[])

  const coords = route.map(r=>[r.Latitude,r.Longitude])

  return(
    <div>

      {/* Manual Input */}
      <div className="card">
        <h3>Update Bin</h3>
        <input placeholder="Bin ID" onChange={e=>setBinId(e.target.value)}/>
        <input placeholder="Waste %" onChange={e=>setWaste(e.target.value)}/>
        <button onClick={()=>{
          fetch("http://127.0.0.1:5000/update",{
            method:"POST",
            headers:{'Content-Type':'application/json'},
            body:JSON.stringify({Bin_ID:binId,Waste_Level:Number(waste)})
          }).then(()=>window.location.reload())
        }}>Update</button>
      </div>

      <MapContainer center={[12.97,77.59]} zoom={11} className="map">
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"/>

        <HeatmapLayer bins={bins}/>

        {bins.map(b=>(
          <Marker
            key={b.Bin_ID}
            position={[b.Latitude,b.Longitude]}
            eventHandlers={{click:()=>setSelected(b)}}
          />
        ))}

        {selected && (
          <CircleMarker
            center={[selected.Latitude,selected.Longitude]}
            radius={30}
            pathOptions={{color:"yellow"}}
          />
        )}

        <Polyline positions={coords} color="blue"/>

      </MapContainer>

    </div>
  )
}
